"use strict";(self.webpackChunktemporal_documentation=self.webpackChunktemporal_documentation||[]).push([["78837"],{26006(e){e.exports=JSON.parse('{"tag":{"label":"Security","permalink":"/tags/security","allTagsPath":"/tags","count":28,"items":[{"id":"cloud/manage-access/index","title":"Account access","description":"Manage access to your Temporal Cloud account","permalink":"/cloud/manage-access/"},{"id":"cloud/audit-logs","title":"Audit Logs","description":"Audit Logs in Temporal Cloud provide forensic information, integrating with a data streaming service for secure data handling and supporting key Admin and API Key operations. This streamlines audit and compliance processes.","permalink":"/cloud/audit-logs"},{"id":"cloud/get-started/certificates","title":"Authenticate with mTLS certificates","description":"Temporal Cloud supports mTLS, which requires CA certificates for secure communication. Keep certificates updated to avoid disruptions in Workflow Execution. Manage and update certificates easily via the Temporal Cloud UI or tcld tool.","permalink":"/cloud/certificates"},{"id":"encyclopedia/data-conversion/codec-server","title":"Codec Server","description":"A Codec Server is an HTTP server that provides remote encoding and decoding for Temporal Payloads.","permalink":"/codec-server"},{"id":"production-deployment/data-encryption","title":"Codec Server - Temporal Platform feature guide","description":"Encrypt data in Temporal Server to secure Workflow, Activity, and Worker information. Use custom Payload Codecs for encryption/decryption, set up Codec Servers for remote decoding, and ensure secure access.","permalink":"/production-deployment/data-encryption"},{"id":"develop/dotnet/converters-and-encryption","title":"Converters and encryption - .NET SDK","description":"Use a custom Payload Codec and Converter in the .NET SDK to modify Temporal Data Conversion behavior, including examples for encryption and camel case conversion.","permalink":"/develop/dotnet/converters-and-encryption"},{"id":"develop/go/converters-and-encryption","title":"Converters and encryption - Go SDK","description":"Use a custom Payload Codec and Payload Converter in Go. Create custom PayloadCodec implementations, set Data Converters, and apply transformations effectively using the Temporal SDK.","permalink":"/develop/go/converters-and-encryption"},{"id":"develop/java/converters-and-encryption","title":"Converters and encryption - Java SDK","description":"Create and implement a Custom Payload Codec and Payload Converter in Java using the Temporal SDK for custom data encryption, compression, and type conversion.","permalink":"/develop/java/converters-and-encryption"},{"id":"develop/python/converters-and-encryption","title":"Converters and encryption - Python SDK","description":"Use custom Payload Codecs and Converters with Temporal Python SDK for enhanced Workflow data handling, including custom encoding steps like compression and encryption. Discover how to implement and set up custom Data Converters to convert Temporal payloads efficiently and support various data types.","permalink":"/develop/python/converters-and-encryption"},{"id":"develop/ruby/converters-and-encryption","title":"Converters and encryption - Ruby SDK","description":"Use a custom Payload Codec and Converter in the Ruby SDK to modify Temporal Data Conversion behavior, including examples for encryption and formatting.","permalink":"/develop/ruby/converters-and-encryption"},{"id":"develop/typescript/converters-and-encryption","title":"Converters and encryption - TypeScript SDK","description":"Create a custom Payload Converter in TypeScript with Temporal SDKs to handle non-JSON-serializable values, configure your Data Converter, and use protobufs and encryption seamlessly in your Workflows and Activities.","permalink":"/develop/typescript/converters-and-encryption"},{"id":"evaluate/development-production-features/data-encryption","title":"Data encryption - Temporal feature","description":"Implement data encryption in your Temporal Workflows to ensure the security and confidentiality of your data.","permalink":"/evaluate/development-production-features/data-encryption"},{"id":"encyclopedia/data-conversion/default-custom-data-converters","title":"Default and Custom Data Converters","description":"Learn about the default Data Converter in Temporal SDKs and how to implement a custom Data Converter for custom serialization and encoding needs.","permalink":"/default-custom-data-converters"},{"id":"encyclopedia/data-conversion/failure-converter","title":"Failure Converter","description":"A Failure Converter transforms error messages and call stacks into encoded formats to enhance security and observability.","permalink":"/failure-converter"},{"id":"encyclopedia/data-conversion/dataconversion","title":"How does Temporal handle application data?","description":"This guide explores Data Converters in the Temporal Platform, detailing how they handle serialization and encoding for Workflow inputs and outputs, ensuring data stays secure and manageable.","permalink":"/dataconversion"},{"id":"encyclopedia/data-conversion/key-management","title":"Key management","description":"Learn about key management practices for securing encryption keys in Temporal applications.","permalink":"/key-management"},{"id":"cloud/get-started/user-groups","title":"Manage user groups","description":"Learn how to manage user groups, members, and roles","permalink":"/cloud/user-groups"},{"id":"best-practices/cloud-access-control","title":"Managing Temporal Cloud access control","description":"Best practices for managing access control, permissions, and user management in Temporal Cloud.","permalink":"/best-practices/cloud-access-control"},{"id":"cloud/notifications","title":"Notifications","description":"Receive updates about Temporal Cloud including when certificates will expire, billing updates, and when a failover has completed.","permalink":"/cloud/notifications"},{"id":"encyclopedia/data-conversion/payload-codec","title":"Payload Codec","description":"A Payload Codec performs bytes-to-bytes transformations on Temporal Payloads, often for compression and encryption.","permalink":"/payload-codec"},{"id":"encyclopedia/data-conversion/payload-converter","title":"Payload Converter","description":"A Payload Converter serializes and deserializes values to and from bytes for use in the Temporal SDK.","permalink":"/payload-converter"},{"id":"encyclopedia/data-conversion/remote-data-encoding","title":"Remote data encoding","description":"Use remote encoding to transform data for the Temporal CLI and Web UI.","permalink":"/remote-data-encoding"},{"id":"cloud/saml","title":"SAML authentication","description":"Integrate SAML 2.0 with your Temporal Cloud account for secure user authentication. Connect via Microsoft Entra ID or Okta and ensure seamless SSO. Charges apply.","permalink":"/cloud/saml"},{"id":"cloud/scim","title":"SCIM user management","description":"Link your IdP with your Temporal Cloud account to securely automate user and group management.","permalink":"/cloud/scim"},{"id":"best-practices/security-controls","title":"Security controls for Temporal Cloud","description":"Best practices for implementing and managing security controls in Temporal Cloud environments.","permalink":"/best-practices/security-controls"},{"id":"evaluate/temporal-cloud/security","title":"Security model - Temporal Cloud","description":"Temporal Cloud provides robust security for applications, data, and its platform with features like mTLS, client-side encryption, PrivateLink, and SOC 2 Type 2 compliance.","permalink":"/cloud/security"},{"id":"security","title":"Temporal Platform security","description":"Discover general security practices of Temporal Technologies, SaaS security with Temporal Cloud, and how to self-host a secure Temporal Platform on our security pages.","permalink":"/security"},{"id":"production-deployment/self-hosted-guide/security","title":"Temporal Platform security features","description":"Discover comprehensive security features of the Temporal Platform, including secure network communication with TLS and mTLS, robust authentication, customizable authorization, and single sign-on integration to protect your data and operations.","permalink":"/self-hosted-guide/security"}],"unlisted":false}}')}}]);